SELECT toTypeName(opt_id), opt_id, toTypeName(arr_id), arr_id
FROM format(Arrow, 'opt_id Nullable(UUID), arr_id Array(Nullable(UUID))', base64Decode(''))
ORDER BY opt_id ASC;
